class Solution:
    def maxAlternatingSum(self, nums, swaps):
        n = len(nums)
        parent = list(range(n))
        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        for a, b in swaps:
            ra, rb = find(a), find(b)
            if ra != rb:
                parent[ra] = rb
        from collections import defaultdict
        comp_vals = defaultdict(list)
        comp_even = defaultdict(int)
        for i in range(n):
            r = find(i)
            comp_vals[r].append(nums[i])
            if i % 2 == 0:
                comp_even[r] += 1
        total = 0
        for r, vals in comp_vals.items():
            vals.sort()
            e = comp_even[r]
            # smallest go to minus, largest go to plus
            minus = vals[:len(vals) - e]
            plus = vals[len(vals) - e:]
            total += sum(plus) - sum(minus)
        return total

