class Solution:
    def maxAlternatingSum(self, nums, swaps):
        n = len(nums)
        parent = list(range(n))
        rank = [0] * n
        def find(x):
            root = x
            while parent[root] != root:
                root = parent[root]
            while parent[x] != root:
                parent[x], x = root, parent[x]
            return root
        for a, b in swaps:
            ra, rb = find(a), find(b)
            if ra != rb:
                if rank[ra] < rank[rb]:
                    ra, rb = rb, ra
                parent[rb] = ra
                if rank[ra] == rank[rb]:
                    rank[ra] += 1
        groups = {}
        for i in range(n):
            r = find(i)
            if r not in groups:
                groups[r] = [[], 0]
            groups[r][0].append(nums[i])
            if i % 2 == 0:
                groups[r][1] += 1
        total = 0
        for vals, e in groups.values():
            vals.sort(reverse=True)
            for idx, v in enumerate(vals):
                if idx < e:
                    total += v
                else:
                    total -= v
        return total

