var maxAlternatingSum = function(nums, swaps) {
    const n = nums.length;
    const parent = Array.from({length: n}, (_, i) => i);
    const rank = new Array(n).fill(0);
    const find = (x) => {
        let root = x;
        while (parent[root] !== root) root = parent[root];
        while (parent[x] !== root) { const nx = parent[x]; parent[x] = root; x = nx; }
        return root;
    };
    for (const [a, b] of swaps) {
        let ra = find(a), rb = find(b);
        if (ra !== rb) {
            if (rank[ra] < rank[rb]) { const t = ra; ra = rb; rb = t; }
            parent[rb] = ra;
            if (rank[ra] === rank[rb]) rank[ra]++;
        }
    }
    const groups = new Map();
    for (let i = 0; i < n; i++) {
        const r = find(i);
        if (!groups.has(r)) groups.set(r, {vals: [], even: 0});
        const g = groups.get(r);
        g.vals.push(nums[i]);
        if (i % 2 === 0) g.even++;
    }
    let total = 0;
    for (const {vals, even} of groups.values()) {
        vals.sort((a, b) => b - a);
        for (let idx = 0; idx < vals.length; idx++) {
            if (idx < even) total += vals[idx]; else total -= vals[idx];
        }
    }
    return total;
};
